const { execSync } = require('child_process');
const item = $input.item.json;
const cmd = `npx playwright test "${item.testPath}" --reporter=json`;
const cwd = 'c:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow';
const startTime = new Date();
let stdout = '', stderr = '', exitCode = 0;
try {
  stdout = execSync(cmd, { cwd, stdio: 'pipe', timeout: 600000 }).toString();
} catch (e) {
  exitCode = e.status || 1;
  stdout = (e.stdout || '').toString();
  stderr = (e.stderr || e.message || '').toString();
}
const duration = ((new Date() - startTime) / 1000).toFixed(2);
let testCases = [], stats = { total: 0, passed: 0, failed: 0 }, jsonErrors = [];
try {
  const jsonMatch = stdout.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const jsonData = JSON.parse(jsonMatch[0]);
    if (jsonData.stats) {
      stats.passed = jsonData.stats.expected || 0;
      stats.failed = jsonData.stats.unexpected || 0;
      stats.total = stats.passed + stats.failed + (jsonData.stats.skipped || 0);
    }
    if (jsonData.suites) {
      jsonData.suites.forEach(suite => {
        (suite.specs || []).forEach(spec => {
          spec.tests.forEach(test => {
            const res = test.results && test.results[0];
            if (res && res.status === 'failed' && res.error) jsonErrors.push(res.error.message);
            testCases.push({ title: spec.title, status: res ? res.status : 'unknown' });
          });
        });
      });
    }
  }
} catch (e) {}
const combined = stdout + '\n' + stderr;
const jsonStart = combined.lastIndexOf('{"stats":');
const logs = jsonStart !== -1 ? combined.substring(0, jsonStart).trim() : combined.trim();
const finalLogs = logs.replace(/\[MCP\] ✅ Called \/\w+/g, '').trim();
let errorDetails = jsonErrors.length > 0 ? "--- CASE ERRORS ---\n" + jsonErrors.join('\n\n') + "\n\n" : '';
if (exitCode !== 0) errorDetails += "--- SYSTEM LOGS ---\n" + finalLogs;
return {
  json: { ...item, exitCode, status: exitCode === 0 ? 'passed' : 'failed', duration: `${duration}s`, timestamp: new Date().toISOString(), stats, testCases, errorDetails: errorDetails || 'Passed', rawStdout: stdout }
};

const item = $input.item.json;
const stdout = item.rawStdout;
const cwd = 'c:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow';
let failures = [];
try {
  const jsonMatch = stdout.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const jsonData = JSON.parse(jsonMatch[0]);
    function processSuite(suite, parents = []) {
      const currentTitle = parents.concat(suite.title || []).filter(t => t);
      (suite.specs || []).forEach(spec => {
        const specTitle = currentTitle.concat(spec.title).join(' > ');
        (spec.tests || []).forEach(test => {
          const res = (test.results || []).find(r => r.status === 'failed' || r.status === 'timedOut');
          if (res) {
            const ss = (res.attachments || []).find(a => a.name === 'screenshot');
            failures.push({
              filename: item.filename, product: item.product, testTitle: specTitle,
              caseError: res.error ? (res.error.stack || res.error.message) : 'Test failed',
              caseDuration: (res.duration / 1000).toFixed(2) + 's',
              screenshotPath: ss ? (ss.path.includes(':') || ss.path.startsWith('/') ? ss.path : `${cwd}/${ss.path}`).replace(/\\/g, '/') : null,
              timestamp: item.timestamp
            });
          }
        });
      });
      if (suite.suites) suite.suites.forEach(s => processSuite(s, currentTitle));
    }
    if (jsonData.suites) jsonData.suites.forEach(s => processSuite(s));
  }
} catch (err) {}
if (failures.length === 0 && item.status === 'failed') {
  failures.push({ filename: item.filename, product: item.product, testTitle: 'Execution Error', caseError: item.errorDetails, caseDuration: item.duration, screenshotPath: null, timestamp: item.timestamp });
}
return failures.map(f => ({ json: f }));

