const fs = require('fs');
const path = require('path');
const resultsDir = 'C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';
const files = fs.readdirSync(resultsDir).filter(f => f.startsWith('test_') && f.endsWith('.json'));
let totalCases = 0, passedCases = 0, totalFiles = files.length, product = 'ERP';
let allTestCases = [];
files.forEach(f => {
  const data = JSON.parse(fs.readFileSync(path.join(resultsDir, f)));
  totalCases += (data.stats ? data.stats.total : 1);
  passedCases += (data.stats ? data.stats.passed : (data.exitCode === 0 ? 1 : 0));
  product = data.product || product;
  if (data.testCases) data.testCases.forEach(tc => allTestCases.push({ ...tc, filename: data.filename }));
});
const successRate = totalCases > 0 ? ((passedCases / totalCases) * 100).toFixed(2) : 0;
return { json: { product, totalFiles, totalCases, passedCases, failedCases: totalCases - passedCases, successRate, allTestCases, timestamp: new Date().toLocaleString() } };
